import React from 'react';
import { Button, Checkbox, Input, SearchInput, Select } from '@linm-soft-org/linm-web-common-components';
import { CustomerSearchField, AccountSearchInput, ContractSearchField, useAccountSearchAsOfDate } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import {
  CurrencyPairField,
  useVoucherHeaderCompact,
  VoucherDescriptionField,
  VoucherFormRow,
} from '../../../../../components/voucher';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import styles from '../../../../../styles/documentForm.module.css';

export const CashVoucherHeaderSection: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const {
    kind,
    labels,
    receiptKind,
    setReceiptKind,
    receiptKindOpts,
    receiptKindLocked,
    tid,
    viewSectionClass,
    voucherDate,
    setVoucherDate,
    fieldErrors,
    patchHeaderFieldError,
    fieldLockProps,
    voucherNumber,
    ph,
    staticFieldProps,
    fmLegacyCode,
    currencyCode,
    currencyOptions,
    exchangeRate,
    headerExpanded,
    setHeaderExpanded,
    showHeaderCustomer,
    customerId,
    customerCode,
    customerName,
    representativeName,
    setCustomerId,
    setCustomerCode,
    setCustomerName,
    setRepresentativeName,
    customerPhone,
    setCustomerPhone,
    searchFieldClass,
    searchDisabled,
    reference,
    referenceCustomerName,
    setReference,
    setReferenceCustomerName,
    showAllocateBtn,
    setShowAllocateModal,
    isReadOnly,
    accountCode,
    accountName,
    setAccountCode,
    setAccountName,
    showCounterAccountHeader,
    counterAccountCode,
    counterAccountName,
    setCounterAccountCode,
    setCounterAccountName,
    description,
    setDescription,
    postingReasonCode,
    paymentChannelCode,
    postingReasonSearchConfig,
    paymentChannelSearchConfig,
    selectedPostingReason,
    selectedPaymentChannel,
    handlePostingReasonSelect,
    handlePostingReasonClear,
    handlePaymentChannelSelect,
    handlePaymentChannelClear,
    showAllowEditPostingCheckbox,
    allowEditPostingAccounts,
    handleAllowEditPostingAccountsChange,
    postingAccountsLocked,
    textareaClassName,
    textareaReadOnly,
    textareaDisabled,
    selectDisabled,
  } = vm;

  /** §8.10.3 — PT: Ngày + Loại + ĐT + TK; PC: Ngày + ĐT + TK (`cash-voucher-header-compact-map.md`) */
  const useCompactHeader = kind === 'receipt' || kind === 'payment';
  const accountSearchOptions = useAccountSearchAsOfDate(voucherDate);
  const postingReasonName = selectedPostingReason?.name ?? '';
  const paymentChannelName = selectedPaymentChannel?.name ?? '';
  const accountSearchDisabled = searchDisabled || postingAccountsLocked;

  const compact = useVoucherHeaderCompact({
    enabled: useCompactHeader,
    headerExpanded,
    styles: {
      field: styles.field,
      headerCompactHidden: styles.headerCompactHidden,
      headerCompactActive: styles.headerCompactActive,
    },
  });
  const formRowStyles = { row4: styles.row4 };

  const headerToggle = useCompactHeader ? (
    <button
      type="button"
      className={styles.headerToggleBtn}
      data-testid={tid(headerExpanded ? 'header-collapse' : 'header-expand')}
      aria-expanded={headerExpanded}
      onClick={() => setHeaderExpanded(v => !v)}
    >
      <span className={styles.headerToggleIcon} aria-hidden>
        <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
      </span>
      {headerExpanded ? labels.headerCollapse : labels.headerExpand}
    </button>
  ) : null;

  const sectionClass = [styles.section, viewSectionClass, compact.headerCompactSectionClass]
    .filter(Boolean)
    .join(' ');

  return (
    <div
      className={sectionClass}
      id={tid('section-header')}
      data-testid={tid('section-header')}
    >
      <div className={styles.sectionTitleRow}>
        <h2 className={styles.sectionTitle}>{labels.sectionHeader}</h2>
        {headerToggle}
      </div>

      <div className={styles.headerFieldsFlow}>
        <VoucherFormRow styles={formRowStyles}>
          {kind === 'receipt' && (
            <div className={compact.fieldClass(compact.compactHideClass(true))}>
              <label className={styles.label}>{labels.receiptKind}</label>
              <Select
                data-testid={tid('field-receiptKind')}
                options={receiptKindOpts}
                value={receiptKind}
                onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setReceiptKind(e.target.value)}
                disabled={selectDisabled || receiptKindLocked}
              />
            </div>
          )}
          <div
            id={tid('field-voucherDate')}
            className={compact.fieldClass(compact.compactHideClass(true))}
            data-testid={tid('field-voucherDate')}
          >
            <label className={styles.label}>{labels.voucherDate} *</label>
            <Input
              type="date"
              value={voucherDate}
              error={fieldErrors.voucherDate}
              onChange={e => {
                const v = e.target.value;
                setVoucherDate(v);
                patchHeaderFieldError('voucherDate', v);
              }}
              {...fieldLockProps}
            />
          </div>
          <div className={compact.fieldClass(compact.compactHideClass(false))}>
            <label className={styles.label}>{labels.voucherCode}</label>
            <Input value={voucherNumber} placeholder={ph('Tự động sinh')} {...staticFieldProps} />
          </div>
          {fmLegacyCode ? (
            <div
              className={compact.fieldClass(compact.compactHideClass(false))}
              data-testid={tid('field-legacyCode')}
            >
              <label className={styles.label}>{labels.legacyCode}</label>
              <Input value={fmLegacyCode} {...staticFieldProps} />
            </div>
          ) : null}
          <CurrencyPairField
            className={compact.fieldClass(compact.compactHideClass(false))}
            currencyCode={currencyCode}
            exchangeRate={exchangeRate}
            currencyOptions={currencyOptions}
            staticFieldProps={staticFieldProps}
            selectDisabled={selectDisabled}
            currencyLabel={labels.currency}
            exchangeRateLabel={labels.exchangeRate}
            testId={tid}
          />
        </VoucherFormRow>

        <VoucherFormRow styles={formRowStyles}>
          {showHeaderCustomer && (
            <div
              id={tid('field-customerId')}
              className={compact.fieldClass(styles.spanCol2, compact.compactHideClass(true))}
              data-testid={tid('field-customerId')}
            >
              <label className={styles.label}>{labels.partnerLabel}</label>
              <CustomerSearchField
                testIdPrefix={tid('customer')}
                className={searchFieldClass}
                customerId={customerId}
                customerCode={customerCode}
                customerName={customerName}
                onSelect={c => {
                  setCustomerId(c.customerId);
                  setCustomerCode(c.code);
                  setCustomerName(c.name);
                  setRepresentativeName(c.name);
                  setCustomerPhone(c.phone ?? '');
                }}
                onClear={() => {
                  setCustomerId('');
                  setCustomerCode('');
                  setCustomerName('');
                  setCustomerPhone('');
                }}
                placeholder={ph('Nhập mã hoặc tên đối tượng...')}
                disabled={searchDisabled}
              />
            </div>
          )}
          <div
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-customerPhone')}
          >
            <label className={styles.label}>{labels.customerPhone}</label>
            <Input
              value={customerPhone}
              onChange={e => setCustomerPhone(e.target.value)}
              {...fieldLockProps}
            />
          </div>
          {showHeaderCustomer && (
            <div
              className={compact.fieldClass(compact.compactHideClass(false))}
              data-testid={tid('field-representativeName')}
            >
              <label className={styles.label}>{labels.representativeLabel}</label>
              <Input
                value={representativeName}
                onChange={e => setRepresentativeName(e.target.value)}
                {...fieldLockProps}
              />
            </div>
          )}
          <div className={compact.fieldClass(compact.compactHideClass(false))}>
            <label className={styles.label}>
              {labels.reference}
              {receiptKind === '1' ? ' *' : ''}
            </label>
            <ContractSearchField
              className={searchFieldClass}
              contractCode={reference}
              customerName={referenceCustomerName}
              onSelect={(code, name) => {
                setReference(code);
                setReferenceCustomerName(name);
              }}
              onClear={() => {
                setReference('');
                setReferenceCustomerName('');
              }}
              disabled={searchDisabled}
              placeholder={ph('Nhập mã hợp đồng...')}
            />
          </div>
        </VoucherFormRow>

        {showAllocateBtn && (
          <VoucherFormRow styles={formRowStyles}>
            <div className={compact.fieldClass(compact.compactHideClass(false))}>
              <Button
                variant="secondary"
                type="button"
                data-testid={tid('allocate-invoices-btn')}
                onClick={() => setShowAllocateModal(true)}
                disabled={isReadOnly}
              >
                {labels.allocateInvoices}
              </Button>
            </div>
          </VoucherFormRow>
        )}

        <VoucherFormRow styles={formRowStyles}>
          <div
            id={tid('field-postingReasonCode')}
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-postingReasonCode')}
          >
            <label className={styles.label}>{labels.postingReasonCode}</label>
            <SearchInput
              config={postingReasonSearchConfig}
              value={postingReasonCode}
              primaryDisplay={postingReasonCode}
              secondaryDisplay={postingReasonName}
              onChange={handlePostingReasonSelect}
              onClear={handlePostingReasonClear}
              className={searchFieldClass}
              showLabel={false}
              disabled={searchDisabled}
              placeholder={ph('Chọn lý do định khoản...')}
            />
          </div>
          <div
            id={tid('field-paymentChannelCode')}
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-paymentChannelCode')}
          >
            <label className={styles.label}>{labels.paymentChannelCode}</label>
            <SearchInput
              config={paymentChannelSearchConfig}
              value={paymentChannelCode}
              primaryDisplay={paymentChannelCode}
              secondaryDisplay={paymentChannelName}
              onChange={handlePaymentChannelSelect}
              onClear={handlePaymentChannelClear}
              className={searchFieldClass}
              showLabel={false}
              disabled={searchDisabled}
              placeholder={ph('Chọn hình thức thanh toán...')}
            />
          </div>
          {showAllowEditPostingCheckbox && (
            <div
              className={compact.fieldClass(compact.compactHideClass(false))}
              data-testid={tid('field-allowEditPostingAccounts')}
            >
              <Checkbox
                label={labels.allowEditPostingAccounts}
                checked={allowEditPostingAccounts}
                onChange={e => handleAllowEditPostingAccountsChange(e.target.checked)}
                disabled={selectDisabled}
                data-testid={tid('field-allowEditPostingAccounts-cb')}
              />
            </div>
          )}
        </VoucherFormRow>

        <VoucherFormRow styles={formRowStyles}>
          <div
            id={tid('field-accountCode')}
            className={compact.fieldClass(compact.compactHideClass(true))}
            data-testid={tid('field-accountCode')}
          >
            <label className={styles.label}>{labels.cashLabel} *</label>
            <AccountSearchInput
              api={erpFinanceAccountSearchApi}
              configOptions={accountSearchOptions}
              className={searchFieldClass}
              value={accountCode}
              primaryDisplay={formatAccountDisplay(accountCode, accountName)}
              error={fieldErrors.accountCode}
              onChange={a => {
                setAccountCode(a.code);
                setAccountName(a.name);
                patchHeaderFieldError('accountCode', a.code);
              }}
              onClear={() => {
                setAccountCode('');
                setAccountName('');
                patchHeaderFieldError('accountCode', '');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder={ph('Mã hoặc tên TK...')}
              disabled={accountSearchDisabled}
            />
          </div>
          {showCounterAccountHeader && (
            <div
              className={compact.fieldClass(styles.spanCol2, compact.compactHideClass(false))}
              data-testid={tid('field-counterAccountCode')}
            >
              <label className={styles.label}>{labels.lineThAccount} *</label>
              <AccountSearchInput
                api={erpFinanceAccountSearchApi}
                configOptions={accountSearchOptions}
                className={searchFieldClass}
                value={counterAccountCode}
                primaryDisplay={formatAccountDisplay(counterAccountCode, counterAccountName)}
                onChange={a => {
                  setCounterAccountCode(a.code);
                  setCounterAccountName(a.name);
                }}
                onClear={() => {
                  setCounterAccountCode('');
                  setCounterAccountName('');
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder={ph('TK đối ứng...')}
                disabled={accountSearchDisabled}
              />
            </div>
          )}
          {!showCounterAccountHeader && (
            <div
              id={tid('field-description')}
              className={compact.fieldClass(styles.spanCol3, compact.compactHideClass(false))}
              data-testid={tid('field-description')}
            >
              <label className={styles.label}>{labels.description}</label>
              <VoucherDescriptionField
                data-testid={tid('field-description-input')}
                value={description}
                error={fieldErrors.description}
                placeholder={ph('Nhập diễn giải...')}
                className={textareaClassName}
                onChange={v => {
                  setDescription(v);
                  patchHeaderFieldError('description', v);
                }}
                readOnly={textareaReadOnly}
                disabled={textareaDisabled}
              />
            </div>
          )}
        </VoucherFormRow>

        {showCounterAccountHeader && (
          <VoucherFormRow styles={formRowStyles}>
            <div
              id={tid('field-description')}
              className={compact.fieldClass(styles.spanCol4, compact.compactHideClass(false))}
              data-testid={tid('field-description')}
            >
              <label className={styles.label}>{labels.description}</label>
              <VoucherDescriptionField
                data-testid={tid('field-description-input')}
                value={description}
                error={fieldErrors.description}
                placeholder={ph('Nhập diễn giải...')}
                className={textareaClassName}
                onChange={v => {
                  setDescription(v);
                  patchHeaderFieldError('description', v);
                }}
                readOnly={textareaReadOnly}
                disabled={textareaDisabled}
              />
            </div>
          </VoucherFormRow>
        )}
      </div>
    </div>
  );
};
