import { utcToLocalInputValue, localInputToISOWithOffset } from '@linm-soft-org/linm-web-common-components';
import { FormMode } from '../../../../../components/form';
import type { VoucherFormSnapshot } from '../../../../../components/voucher';
import type { CashVoucherDto, CreateCashVoucherDto } from '../../../../../services/kt/models';
import type { CashVoucherKind } from '../../../../../components/kt/CashVoucherList';
import type { CashVoucherConfig } from '../config/cashVoucherConfig';
import {
  headerModelFromFields,
  initHeaderFields,
  initLineFields,
  linesModelsFromState,
  newLineId,
  type CashVoucherLineFieldState,
} from '../reducer/fieldHelpers';
import type { CashVoucherHeaderKey } from '../types/cashVoucherHeader.types';
import type { CashVoucherFormReducerState } from '../types/cashVoucherFormState.types';
import type { IField } from '../types/field.types';
import type { CashVoucherLineModel } from '../types/cashVoucherLine.types';

/** `type="date"` cần YYYY-MM-DD. */
export function toDateOnlyInputValue(value: string | null | undefined): string {
  if (!value) return '';
  const trimmed = value.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(trimmed)) return trimmed;
  if (/^\d{4}-\d{2}-\d{2}T/.test(trimmed)) return trimmed.slice(0, 10);
  return utcToLocalInputValue(trimmed).slice(0, 10);
}

export function mapDtoToLineModels(v: CashVoucherDto, kind: CashVoucherKind): CashVoucherLineModel[] {
  return v.lines.map(l => ({
    accountCode: kind === 'receipt' ? l.creditAccountCode : l.debitAccountCode,
    accountName: l.counterAccountName ?? '',
    debitAmount: l.amount,
    description: l.description ?? '',
    costCenterCode: l.costCenterCode ?? '',
    customerId: l.customerId ?? '',
    customerCode: '',
    customerName: '',
    invoiceCode: l.invoiceCode ?? '',
    invoiceDate: toDateOnlyInputValue(l.invoiceDate),
    invoiceTotalAmount: l.invoiceTotalAmount ?? 0,
    invoicePaidAmount: l.invoicePaidAmount ?? 0,
    invoiceRemainingAmount: l.invoiceRemainingAmount ?? 0,
  }));
}

export function buildSnapshotFromState(
  state: CashVoucherFormReducerState,
  opts: { showInvoiceGrid: boolean },
): VoucherFormSnapshot {
  const h = headerModelFromFields(state.header);
  const lineModels = linesModelsFromState(state.lines);
  return {
    voucherDate: h.voucherDate,
    receiptKind: h.receiptKind,
    customerId: h.customerId,
    customerCode: h.customerCode,
    customerName: h.customerName,
    representativeName: h.representativeName,
    customerPhone: h.customerPhone,
    reference: h.reference,
    referenceCustomerName: h.referenceCustomerName,
    accountCode: h.accountCode,
    accountName: h.accountName,
    counterAccountCode: h.counterAccountCode,
    counterAccountName: h.counterAccountName,
    description: h.description,
    processingLevel: h.processingLevel,
    postingReasonCode: h.postingReasonCode,
    paymentChannelCode: h.paymentChannelCode,
    lines: lineModels.map(l => ({
      accountCode: opts.showInvoiceGrid ? h.counterAccountCode : l.accountCode,
      accountName: opts.showInvoiceGrid ? h.counterAccountName : l.accountName,
      debitAmount: Number(l.debitAmount) || 0,
      description: l.description,
      costCenterCode: l.costCenterCode,
      customerId: l.customerId,
      customerCode: l.customerCode,
      customerName: l.customerName,
      invoiceCode: l.invoiceCode,
      invoiceDate: l.invoiceDate,
      invoiceTotalAmount: l.invoiceTotalAmount,
      invoicePaidAmount: l.invoicePaidAmount,
      invoiceRemainingAmount: l.invoiceRemainingAmount,
    })),
  };
}

export function mapDtoToFormInit(
  v: CashVoucherDto,
  kind: CashVoucherKind,
): {
  header: Record<CashVoucherHeaderKey, IField<string>>;
  lines: CashVoucherLineFieldState[];
  snap: VoucherFormSnapshot;
} {
  const voucherDateLocal = toDateOnlyInputValue(v.voucherDate);
  const lineModels = mapDtoToLineModels(v, kind);
  const firstLine = lineModels[0];
  const headerValues = {
    voucherDate: voucherDateLocal,
    voucherNumber: v.code,
    receiptKind: v.receiptKind || '2',
    currencyCode: v.currencyCode ?? '',
    exchangeRate: String(v.exchangeRate ?? ''),
    customerId: v.customerId ?? '',
    customerCode: v.customerCode ?? '',
    customerName: v.customerName ?? '',
    representativeName: v.representativeName ?? '',
    customerPhone: v.customerPhone ?? '',
    reference: v.referenceNo ?? '',
    referenceCustomerName: v.referenceCustomerName ?? '',
    accountCode: v.accountCode,
    accountName: v.accountName ?? '',
    counterAccountCode:
      kind === 'receipt' && (v.receiptKind || '2') === '1' && firstLine
        ? firstLine.accountCode
        : '',
    counterAccountName:
      kind === 'receipt' && (v.receiptKind || '2') === '1' && firstLine
        ? firstLine.accountName
        : '',
    description: v.description ?? '',
    processingLevel: v.processingLevel || '3',
    postingReasonCode: v.postingReasonCode ?? '',
    paymentChannelCode: v.paymentChannelCode ?? '',
  };
  const header = initHeaderFields(headerValues);
  const lines =
    lineModels.length > 0
      ? lineModels.map(m => initLineFields(m, newLineId()))
      : [initLineFields(
        {
          accountCode: '',
          accountName: '',
          debitAmount: 0,
          description: '',
          costCenterCode: '',
          customerId: '',
          customerCode: '',
          customerName: '',
          invoiceCode: '',
          invoiceDate: '',
          invoiceTotalAmount: 0,
          invoicePaidAmount: 0,
          invoiceRemainingAmount: 0,
        },
        newLineId(),
      )];
  const snap = buildSnapshotFromState(
    {
      header,
      lines,
      meta: { status: v.status, savedSnapshot: null, fieldErrors: {}, generalErrors: [] },
      formMode: FormMode.View,
    },
    { showInvoiceGrid: kind === 'receipt' && (v.receiptKind || '2') === '1' },
  );
  return { header, lines, snap };
}

export function mapFormStateToPayload(
  state: CashVoucherFormReducerState,
  cfg: CashVoucherConfig,
  kind: CashVoucherKind,
  opts: { showInvoiceGrid: boolean; totalAmount: number },
): CreateCashVoucherDto {
  const h = headerModelFromFields(state.header);
  const lineModels = linesModelsFromState(state.lines);
  const buildLines = (cash: string) =>
    lineModels.map(l => {
      const counter = opts.showInvoiceGrid ? h.counterAccountCode : l.accountCode;
      return {
        debitAccountCode: kind === 'receipt' ? cash : counter,
        creditAccountCode: kind === 'receipt' ? counter : cash,
        amount: Number(l.debitAmount),
        description: l.description || undefined,
        customerId: l.customerId || undefined,
        costCenterCode: l.costCenterCode || undefined,
        invoiceCode: l.invoiceCode || undefined,
      };
    });
  return {
    voucherDate: localInputToISOWithOffset(h.voucherDate),
    voucherType: cfg.voucherType,
    receiptKind: h.receiptKind,
    customerId: h.customerId || undefined,
    representativeName: h.representativeName?.trim() || undefined,
    accountCode: h.accountCode,
    description: h.description || undefined,
    amount: opts.totalAmount,
    currencyCode: h.currencyCode,
    exchangeRate: Number(h.exchangeRate) || 1,
    referenceNo: h.reference || undefined,
    processingLevel: h.processingLevel,
    postingReasonCode: h.postingReasonCode?.trim() || undefined,
    paymentChannelCode: h.paymentChannelCode?.trim() || undefined,
    lines: buildLines(h.accountCode),
  };
}
